function solve(c: number, connections: number[][], queries: number[][]): number[] {
    class MinHeap {
        heap: number[];
        constructor() {
            this.heap = [];
        }
        push(val: number): void {
            this.heap.push(val);
            this.bubbleUp(this.heap.length - 1);
        }
        private bubbleUp(index: number): void {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[parentIndex] <= this.heap[index]) break;
                [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
                index = parentIndex;
            }
        }
        pop(): number {
            const top = this.heap[0];
            const last = this.heap.pop() as number;
            if (this.heap.length > 0) {
                this.heap[0] = last;
                this.sinkDown(0);
            }
            return top;
        }
        private sinkDown(index: number): void {
            let minIndex = index;
            const left = 2 * index + 1;
            const right = 2 * index + 2;
            if (left < this.heap.length && this.heap[left] < this.heap[minIndex]) {
                minIndex = left;
            }
            if (right < this.heap.length && this.heap[right] < this.heap[minIndex]) {
                minIndex = right;
            }
            if (minIndex !== index) {
                [this.heap[index], this.heap[minIndex]] = [this.heap[minIndex], this.heap[index]];
                this.sinkDown(minIndex);
            }
        }
        peek(): number {
            return this.heap[0];
        }
        size(): number {
            return this.heap.length;
        }
    }

    const graph: number[][] = Array.from({ length: c + 1 }, () => []);
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    const compMap: number[] = new Array(c + 1).fill(-1);
    const components = new Map<number, MinHeap>();
    const onlineStatus: boolean[] = new Array(c + 1).fill(true);
    let compIndex = 0;

    for (let i = 1; i <= c; i++) {
        if (compMap[i] === -1) {
            const queue: number[] = [i];
            const compNodes: number[] = [];
            compMap[i] = compIndex;
            compNodes.push(i);
            let front = 0;
            while (front < queue.length) {
                const node = queue[front];
                front++;
                for (const neighbor of graph[node]) {
                    if (compMap[neighbor] === -1) {
                        compMap[neighbor] = compIndex;
                        compNodes.push(neighbor);
                        queue.push(neighbor);
                    }
                }
            }
            const heap = new MinHeap();
            for (const node of compNodes) {
                heap.push(node);
            }
            components.set(compIndex, heap);
            compIndex++;
        }
    }

    const ans: number[] = [];
    for (const [type, x] of queries) {
        if (type === 1) {
            if (onlineStatus[x]) {
                ans.push(x);
            } else {
                const compId = compMap[x];
                const heap = components.get(compId);
                if (!heap) {
                    ans.push(-1);
                } else {
                    let found = false;
                    while (heap.size() > 0) {
                        const top = heap.peek();
                        if (onlineStatus[top]) {
                            ans.push(top);
                            found = true;
                            break;
                        } else {
                            heap.pop();
                        }
                    }
                    if (!found) {
                        ans.push(-1);
                    }
                }
            }
        } else if (type === 2) {
            onlineStatus[x] = false;
        }
    }
    return ans;
}
