function solve(c: number, connections: number[][], queries: number[][]): number[] {
    class MinHeap {
        heap: number[];

        constructor(initialElements: number[]) {
            this.heap = [...initialElements];
            if (this.heap.length > 0) {
                this.buildHeap();
            }
        }

        private buildHeap() {
            const start = Math.floor((this.heap.length - 1) / 2);
            for (let i = start; i >= 0; i--) {
                this.heapifyDown(i);
            }
        }

        private heapifyDown(startIdx: number) {
            let idx = startIdx;
            while (idx < this.heap.length) {
                const left = 2 * idx + 1;
                const right = 2 * idx + 2;
                let smallest = idx;

                if (left < this.heap.length && this.heap[left] < this.heap[smallest]) {
                    smallest = left;
                }
                if (right < this.heap.length && this.heap[right] < this.heap[smallest]) {
                    smallest = right;
                }
                if (smallest === idx) {
                    break;
                }
                [this.heap[idx], this.heap[smallest]] = [this.heap[smallest], this.heap[idx]];
                idx = smallest;
            }
        }

        pop(): number | undefined {
            if (this.heap.length === 0) {
                return undefined;
            }
            const min = this.heap[0];
            const last = this.heap.pop();
            if (this.heap.length > 0 && last !== undefined) {
                this.heap[0] = last;
                this.heapifyDown(0);
            }
            return min;
        }

        top(): number | undefined {
            if (this.heap.length === 0) {
                return undefined;
            }
            return this.heap[0];
        }

        size(): number {
            return this.heap.length;
        }
    }

    const online = new Array(c + 1).fill(true);
    const parent = Array.from({ length: c + 1 }, (_, i) => i);
    const rank = new Array(c + 1).fill(0);

    const find = (x: number): number => {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    for (const [u, v] of connections) {
        const ru = find(u);
        const rv = find(v);
        if (ru === rv) {
            continue;
        }
        if (rank[ru] < rank[rv]) {
            parent[ru] = rv;
        } else if (rank[rv] < rank[ru]) {
            parent[rv] = ru;
        } else {
            parent[ru] = rv;
            rank[rv]++;
        }
    }

    const compRoot = new Array(c + 1);
    for (let i = 1; i <= c; i++) {
        compRoot[i] = find(i);
    }

    const compMap = new Map<number, number[]>();
    for (let i = 1; i <= c; i++) {
        const r = compRoot[i];
        if (!compMap.has(r)) {
            compMap.set(r, []);
        }
        compMap.get(r)!.push(i);
    }

    const heapMap = new Map<number, MinHeap>();
    for (const [r, nodes] of compMap.entries()) {
        heapMap.set(r, new MinHeap(nodes));
    }

    const ans: number[] = [];
    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                ans.push(x);
            } else {
                const r = compRoot[x];
                const heap = heapMap.get(r);
                if (!heap) {
                    ans.push(-1);
                } else {
                    while (heap.size() > 0) {
                        const top = heap.top()!;
                        if (online[top]) {
                            break;
                        } else {
                            heap.pop();
                        }
                    }
                    if (heap.size() === 0) {
                        ans.push(-1);
                    } else {
                        ans.push(heap.top()!);
                    }
                }
            }
        } else if (type === 2) {
            online[x] = false;
        }
    }

    return ans;
}
